    24→// --- MOCKS / LOCAL COMPONENTS FOR COCKPIT ---
    25→
    26→const MODULES_DISPLAY = [
    27→  { id: 1, label: 'Idée', sub: 'Brain Dump', icon: Lightbulb },
    28→  { id: 2, label: 'Cadrage', sub: 'BMAD Method', icon: CheckSquare },
    29→  { id: 3, label: 'Features', sub: 'Roadmap', icon: List },
