    34→const ModuleStep = ({ label, icon: Icon, sub, status }: any) => (
    35→  <div className={`flex flex-col items-center gap-2 z-10 ${status === 'active' ? 'opacity-100' : 'opacity-40'}`}>
    36→    <div className="w-8 h-8 rounded-full bg-[#1A1A1A] border border-[var(--border)] flex items-center justify-center text-white">
    37→      <Icon className="w-4 h-4" />
