    46→const CockpitState = ({ onInstantCreate }: { onInstantCreate: (text: string) => void }) => {
    47→  const [idea, setIdea] = useState('');
    48→  const [isGenerating, setIsGenerating] = useState(false);
    49→
    50→  const handleSubmit = () => {
    51→    if (!idea.trim()) return;
    52→    setIsGenerating(true);
    53→    setTimeout(() => {
    54→        onInstantCreate(idea);
    55→    }, 600);
    56→  };
    57→
    58→  return (
    59→    <div className="flex flex-col min-h-[75vh] w-full max-w-[1100px] mx-auto animate-in fade-in duration-500 pt-20 px-6">
    60→      
    61→      {/* HEADER COPY */}
    62→      <div className="text-center mb-12 pt-8">
    63→        <div className="inline-flex items-center gap-2 mb-4 px-3 py-1.5 bg-white/5 border border-white/10 rounded-full">
    64→          <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
    65→          <span className="text-[10px] font-mono text-white/70 uppercase tracking-wider">Accès anticipé ouvert</span>
    66→        </div>
    67→        <h1 className="text-4xl md:text-5xl font-bold text-white mb-5 tracking-tight leading-[1.1]">
    68→          Votre idée mérite mieux que<br/>
    69→          <span className="text-white/60">60 heures perdues dans le chaos.</span>
    70→        </h1>
    71→        <div className="max-w-2xl mx-auto mb-6">
    72→          <p className="text-xl text-white font-semibold mb-3 tracking-tight leading-tight">
    73→            Éliminez l'entropie entre l'idée et l'exécution.
    74→          </p>
    75→          <div className="flex items-center justify-center gap-3 text-xs text-[var(--muted)] font-mono">
    76→            <span>Framework</span>
    77→            <span className="text-[var(--subtle)]">•</span>
    78→            <span>Clarté</span>
    79→            <span className="text-[var(--subtle)]">•</span>
    80→            <span>Package exploitable</span>
    81→          </div>
    82→        </div>
    83→      </div>
    84→
    85→      {/* VALUE PROP SECTION */}
    86→      <div className="mb-12 max-w-3xl mx-auto w-full">
    87→        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
    88→          {[
    89→            { metric: '60h → 2h', label: 'Temps de cadrage' },
    90→            { metric: '0 → 1', label: 'De l\'idée au package' },
    91→            { metric: '100%', label: 'Frameworks intégrés' },
    92→          ].map((item, i) => (
    93→            <div key={i} className="bg-[#0A0A0B] border border-[var(--border)] rounded-lg p-5 text-center hover:border-white/20 transition-all">
    94→              <div className="text-2xl font-bold text-white mb-1 font-mono">{item.metric}</div>
    95→              <div className="text-[10px] text-[var(--subtle)] uppercase tracking-wide">{item.label}</div>
    96→            </div>
    97→          ))}
    98→        </div>
    99→      </div>
   100→
   101→      {/* MAIN COCKPIT CENTERED */}
   102→      <div className="flex flex-col gap-6 flex-1 mb-20 max-w-4xl mx-auto w-full">
   103→        
   104→          {/* Input Panel */}
   105→          <div className="bg-gradient-to-b from-[#111113] to-[#0A0A0B] border border-[var(--border)] rounded-xl p-1 shadow-2xl flex flex-col min-h-[300px] ring-1 ring-white/5">
   106→            <div className="bg-[#0A0A0B] rounded-lg border border-[var(--border)] p-6 flex flex-col flex-1">
   107→              <div className="flex items-center justify-between mb-3">
   108→                <label className="text-xs font-bold text-white uppercase tracking-wide flex items-center gap-2">
   109→                  <Sparkles className="w-3.5 h-3.5" /> Décrivez votre projet
   110→                </label>
   111→                <span className="text-[9px] text-[var(--subtle)] font-mono bg-white/5 px-2 py-0.5 rounded">Gratuit</span>
   112→              </div>
   113→              <textarea
   114→                value={idea}
   115→                onChange={(e) => setIdea(e.target.value)}
   116→                onKeyDown={(e) => {
   117→                  if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) handleSubmit();
   118→                }}
   119→                placeholder="Ex: Un SaaS pour automatiser les rendez-vous des agents immobiliers..."
   120→                className="w-full flex-1 bg-[#050505] border border-[var(--border)] rounded-lg p-4 text-sm text-[var(--text)] placeholder:text-[var(--text-hint)] focus:outline-none focus:border-white/40 focus:ring-2 focus:ring-white/10 resize-none transition-all mb-4 leading-relaxed"
   121→              />
   122→              <div className="flex items-center justify-between">
   123→                <span className="text-[10px] text-[var(--subtle)] font-mono">⌘ + Enter</span>
   124→                <Button
   125→                  onClick={handleSubmit}
   126→                  disabled={!idea.trim() || isGenerating}
   127→                  isLoading={isGenerating}
   128→                  className="bg-white text-black hover:bg-white/90 hover:scale-[1.02] text-sm font-bold px-6 h-10 border-none transition-all shadow-lg"
   129→                >
   130→                  {isGenerating ? 'Génération...' : 'Générer le package'} <ArrowRight className="w-4 h-4 ml-1.5" />
   131→                </Button>
   132→              </div>
   133→            </div>
   134→          </div>
   135→
   136→          {/* Transformation Promise */}
   137→          <div className="bg-[#0A0A0B] border border-[var(--border)] rounded-xl p-6">
   138→            <div className="flex items-center justify-between text-center">
   139→              <div className="flex-1">
   140→                <div className="text-[10px] text-[var(--subtle)] font-mono uppercase tracking-wider mb-2">Avant</div>
   141→                <div className="text-sm text-[var(--muted)]">Idée floue</div>
   142→              </div>
   143→              <div className="px-4">
   144→                <ArrowRight className="w-5 h-5 text-white/40" />
   145→              </div>
   146→              <div className="flex-1">
   147→                <div className="text-[10px] text-[var(--subtle)] font-mono uppercase tracking-wider mb-2">Après</div>
   148→                <div className="text-sm text-white font-medium">Package structuré</div>
   149→              </div>
   150→            </div>
   151→          </div>
   152→
   153→          {/* Journey Flow Visualization */}
   154→          <div className="bg-[#111113] border border-[var(--border)] rounded-xl p-6 flex justify-between items-center relative overflow-hidden">
   155→            {/* Connection Line */}
   156→            <div className="absolute top-1/2 left-6 right-6 h-px bg-[var(--border)] -z-0 transform -translate-y-4"></div>
   157→
   158→            {MODULES_DISPLAY.map((mod, i) => (
   159→              <ModuleStep
   160→                key={mod.id}
   161→                label={mod.label}
   162→                icon={mod.icon}
   163→                sub={mod.sub}
   164→                status={i === 0 ? 'active' : 'todo'}
   165→              />
   166→            ))}
   167→          </div>
   168→
   169→      </div>
   170→
   171→      {/* SOCIAL PROOF SUBTLE */}
   172→      <div className="border-t border-[var(--border)] pt-8 pb-8">
   173→        <div className="flex items-center justify-center gap-6 text-[10px] text-[var(--subtle)] font-mono">
   174→          <span className="flex items-center gap-2">
   175→            <div className="w-1.5 h-1.5 rounded-full bg-green-500/60"></div>
   176→            Validation méthodologique
   177→          </span>
   178→          <span className="flex items-center gap-2">
   179→            <div className="w-1.5 h-1.5 rounded-full bg-green-500/60"></div>
   180→            Framework éprouvé
   181→          </span>
   182→          <span className="flex items-center gap-2">
   183→            <div className="w-1.5 h-1.5 rounded-full bg-green-500/60"></div>
   184→            Zéro BS
   185→          </span>
   186→        </div>
   187→      </div>
   188→
   189→      {/* METHODS SECTION */}
   190→      <div className="border-t border-[var(--border)] pt-12 pb-20">
   191→        <div className="text-center mb-8">
   192→          <h3 className="text-sm font-bold text-white uppercase tracking-widest flex items-center justify-center gap-2 mb-2">
   193→              <BrainCircuit className="w-4 h-4 text-[#A6A6A6]" />
   194→              Creative Engine
   195→          </h3>
   196→          <p className="text-[10px] text-[var(--subtle)] font-mono">5 niveaux de clarification. Frameworks intégrés.</p>
   197→        </div>
   198→        <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
   199→            {Object.values(CREATIVE_MODES).map((mode) => (
   200→                <div key={mode.level} className="bg-[#111113] border border-[#242428] rounded-lg p-4 hover:border-white/20 transition-colors group">
   201→                    <div className="flex items-center justify-between mb-3">
   202→                        <span className="text-[10px] font-mono text-[#525252] border border-[#242428] px-1.5 rounded bg-[#0A0A0B]">LVL {mode.level}</span>
   203→                    </div>
   204→                    <h4 className="text-xs font-bold text-white uppercase tracking-wide mb-1 group-hover:text-white transition-colors">{mode.name}</h4>
   205→                    <p className="text-[10px] text-[#A6A6A6] mb-3 leading-relaxed">{mode.description}</p>
   206→                    <ul className="space-y-1">
   207→                        {mode.methods.slice(0, 3).map((m, i) => (
   208→                            <li key={i} className="text-[9px] text-[#525252] font-mono flex items-center gap-1.5">
   209→                                <span className="w-1 h-1 rounded-full bg-[#242428] group-hover:bg-white/50 transition-colors"></span>
   210→                                {m}
   211→                            </li>
   212→                        ))}
   213→                    </ul>
   214→                </div>
   215→            ))}
   216→        </div>
   217→      </div>
   218→
   219→      {/* BMAD METHOD SECTION */}
   220→      <BmadMethodSection />
   221→
   222→      {/* FINAL CTA SECTION */}
   223→      <div className="border-t border-[var(--border)] pt-16 pb-12 text-center">
   224→        <h2 className="text-xl font-bold text-white mb-3">
   225→          Arrêtez de perdre du temps.<br/>
   226→          Commencez à construire.
   227→        </h2>
   228→        <p className="text-xs text-[var(--subtle)] mb-6 font-mono">
   229→          Accès gratuit. Aucune carte requise.
   230→        </p>
   231→        <Button
   232→          onClick={() => {
   233→            const textarea = document.querySelector('textarea');
   234→            if (textarea) {
   235→              textarea.focus();
   236→              window.scrollTo({ top: 0, behavior: 'smooth' });
   237→            }
   238→          }}
   239→          className="bg-white text-black hover:bg-white/90 hover:scale-[1.02] text-sm font-bold px-8 h-11 border-none transition-all shadow-xl"
   240→        >
   241→          Démarrer maintenant <ArrowRight className="w-4 h-4 ml-2" />
   242→        </Button>
   243→      </div>
   244→    </div>
   245→  );
   246→};
