     2→export const STORAGE_KEYS = {
     3→  PROJECTS: 'buildflow_projects',
     4→  PROFILE: 'buildflow_profile',
     5→  UI_STATE: 'buildflow_ui_state',
     6→};
     7→
     8→const LEGACY_KEYS = {
     9→  PROJECTS: 'prompt_runner_projects',
    10→  PROFILE: 'prompt_runner_profile',
    11→  UI_STATE: 'prompt_runner_ui_state',
    12→};
    13→
    14→// --- HELPERS ROBUSTES ---
    15→
    16→function safeJSONParse<T>(key: string, raw: string | null, fallback: T): T {
    17→  if (!raw || raw === "undefined" || raw === "null") return fallback;
    18→  
    19→  try {
    20→    return JSON.parse(raw);
    21→  } catch (e) {
    22→    console.warn(`[k3rn DB] ⚠️ CORRUPTION DÉTECTÉE pour ${key}.`);
    23→    
    24→    // Quarantaine : on déplace la donnée corrompue pour ne pas la perdre
    25→    if (typeof window !== 'undefined') {
    26→      const corruptKey = `${key}__corrupt__${Date.now()}`;
    27→      try {
    28→        window.localStorage.setItem(corruptKey, raw);
    29→        console.info(`[k3rn DB] Données corrompues déplacées vers ${corruptKey}`);
    30→        
    31→        // Réinitialisation propre
    32→        window.localStorage.setItem(key, JSON.stringify(fallback));
    33→      } catch (writeErr) {
    34→        console.error("[k3rn DB] Impossible d'écrire la quarantaine (Quota ?)", writeErr);
    35→      }
    36→    }
    37→    
    38→    return fallback;
    39→  }
    40→}
    41→
    42→function migrateIfNeeded(newKey: string, oldKey: string) {
    43→  if (typeof window === 'undefined') return;
    44→  
    45→  try {
    46→    const newData = window.localStorage.getItem(newKey);
    47→    const oldData = window.localStorage.getItem(oldKey);
    48→
    49→    // Migration seulement si la nouvelle clé est vide ET l'ancienne existe
    50→    if (!newData && oldData) {
    51→      console.info(`[k3rn DB] Migration de ${oldKey} vers ${newKey}`);
    52→      // On tente un parse pour vérifier l'intégrité avant de copier
    53→      JSON.parse(oldData); 
    54→      window.localStorage.setItem(newKey, oldData);
    55→    }
    56→  } catch (e) {
    57→    console.error(`[k3rn DB] Échec migration ${oldKey} -> ${newKey} (Source corrompue ?)`, e);
    58→  }
    59→}
    60→
    61→// --- API PUBLIQUE ---
    62→
    63→/**
    64→ * Charge une donnée depuis le localStorage avec gestion d'erreurs, quarantaine et migration.
    65→ */
    66→export function loadState<T>(key: string, fallback: T): T {
    67→  if (typeof window === 'undefined') return fallback;
    68→  
    69→  // Tentative de migration avant lecture
    70→  if (key === STORAGE_KEYS.PROJECTS) migrateIfNeeded(STORAGE_KEYS.PROJECTS, LEGACY_KEYS.PROJECTS);
    71→  if (key === STORAGE_KEYS.PROFILE) migrateIfNeeded(STORAGE_KEYS.PROFILE, LEGACY_KEYS.PROFILE);
    72→  if (key === STORAGE_KEYS.UI_STATE) migrateIfNeeded(STORAGE_KEYS.UI_STATE, LEGACY_KEYS.UI_STATE);
    73→
    74→  try {
    75→    const raw = window.localStorage.getItem(key);
    76→    
    77→    if (raw !== null) {
    78→      // Lecture sécurisée
    79→      return safeJSONParse(key, raw, fallback);
    80→    } else {
    81→      // Initialisation (Priming) : on écrit tout de suite la valeur par défaut
    82→      console.debug(`[k3rn DB] Initialisation clé ${key}`);
    83→      window.localStorage.setItem(key, JSON.stringify(fallback));
    84→      return fallback;
    85→    }
    86→  } catch (error) {
    87→    console.warn(`[k3rn DB] Erreur critique chargement ${key}:`, error);
    88→    return fallback;
    89→  }
    90→}
    91→
    92→/**
    93→ * Sauvegarde une donnée dans le localStorage avec gestion d'erreurs.
    94→ */
    95→export function saveState<T>(key: string, state: T): void {
    96→  if (typeof window === 'undefined') return;
    97→
    98→  try {
    99→    const serialized = JSON.stringify(state);
   100→    window.localStorage.setItem(key, serialized);
   101→  } catch (error) {
   102→    console.error(`[k3rn DB] ÉCHEC sauvegarde ${key}:`, error);
   103→    // Ici on pourrait ajouter une gestion "QuotaExceededError" pour alerter l'utilisateur
   104→  }
   105→}
   106→
   107→/**
   108→ * Récupère des infos de debug pour l'UI
   109→ */
   110→export function getDebugInfo() {
   111→  if (typeof window === 'undefined') return { origin: 'server', keys: [] };
   112→  
   113→  return {
   114→    origin: window.location.origin,
   115→    keys: Object.keys(localStorage).filter(k => k.startsWith('buildflow') || k.startsWith('prompt_runner')),
   116→    storageSize: new Blob(Object.values(localStorage)).size
   117→  };
   118→}
