     3→import { User, AuthState, AuthContextType } from './types';
     4→
     5→const AuthContext = createContext<AuthContextType | undefined>(undefined);
     6→
     7→const STORAGE_KEY = 'k3rn_auth_user';
     8→const USERS_STORAGE_KEY = 'k3rn_users'; // Store all registered users
     9→
    10→export function AuthProvider({ children }: { children: ReactNode }) {
    11→  const [authState, setAuthState] = useState<AuthState>({
    12→    user: null,
    13→    isAuthenticated: false,
    14→    isLoading: true,
    15→  });
    16→
    17→  useEffect(() => {
    18→    // Load user from localStorage on mount
    19→    const storedUser = localStorage.getItem(STORAGE_KEY);
    20→    if (storedUser) {
    21→      try {
    22→        const user: User = JSON.parse(storedUser);
    23→        setAuthState({
    24→          user,
    25→          isAuthenticated: true,
    26→          isLoading: false,
    27→        });
    28→      } catch (error) {
    29→        console.error('Failed to parse stored user:', error);
    30→        localStorage.removeItem(STORAGE_KEY);
    31→        setAuthState(prev => ({ ...prev, isLoading: false }));
    32→      }
    33→    } else {
    34→      setAuthState(prev => ({ ...prev, isLoading: false }));
    35→    }
    36→  }, []);
    37→
    38→  const getAllUsers = (): Array<User & { password: string }> => {
    39→    const usersData = localStorage.getItem(USERS_STORAGE_KEY);
    40→    return usersData ? JSON.parse(usersData) : [];
    41→  };
    42→
    43→  const saveUser = (user: User, password: string) => {
    44→    const users = getAllUsers();
    45→    users.push({ ...user, password });
    46→    localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(users));
    47→  };
    48→
    49→  const login = async (email: string, password: string) => {
    50→    // Simulate API delay
    51→    await new Promise(resolve => setTimeout(resolve, 800));
    52→
    53→    const users = getAllUsers();
    54→    const foundUser = users.find(u => u.email === email && u.password === password);
    55→
    56→    if (!foundUser) {
    57→      throw new Error('Email ou mot de passe incorrect');
    58→    }
    59→
    60→    const { password: _, ...user } = foundUser;
    61→
    62→    localStorage.setItem(STORAGE_KEY, JSON.stringify(user));
    63→    setAuthState({
    64→      user,
    65→      isAuthenticated: true,
    66→      isLoading: false,
    67→    });
    68→  };
    69→
    70→  const register = async (email: string, password: string, name: string) => {
    71→    // Simulate API delay
    72→    await new Promise(resolve => setTimeout(resolve, 800));
    73→
    74→    const users = getAllUsers();
    75→    const emailExists = users.some(u => u.email === email);
    76→
    77→    if (emailExists) {
    78→      throw new Error('Cet email est déjà utilisé');
    79→    }
    80→
    81→    const user: User = {
    82→      id: crypto.randomUUID(),
    83→      email,
    84→      name,
    85→      createdAt: new Date().toISOString(),
    86→    };
    87→
    88→    saveUser(user, password);
    89→    localStorage.setItem(STORAGE_KEY, JSON.stringify(user));
    90→    setAuthState({
    91→      user,
