    98→    localStorage.removeItem(STORAGE_KEY);
    99→    setAuthState({
   100→      user: null,
   101→      isAuthenticated: false,
   102→      isLoading: false,
   103→    });
   104→  };
   105→
   106→  return (
   107→    <AuthContext.Provider value={{ ...authState, login, register, logout }}>
   108→      {children}
   109→    </AuthContext.Provider>
   110→  );
   111→}
